/* CourtRcvCstmrMapper.getCrCstmrList */
SELECT TO_CHAR(RSV.REGST_DTTM, 'YYYY-MM-DD') AS FIRST_DT, RCIV2.LAST_DT, TO_CHAR(INOUT.LAST_INOUT_DT, 'YYYY-MM-DD') AS LAST_INOUT_DT, RSV.CSTMR_NAME, CRYPTO_AES256.DEC_AES(RSV.CSTMR_RRN) AS CSTMR_RRN, FN_GET_CODENM('MSP0031', RSV.CR_TP ) AS CR_TP, RSV.CR_COMP, RSV.NO_JUDG, RSV.JUDG_PAN, F_GET_KT_CODE_NM('PPS_VAC', 'BANK_CODE', ACCT.VAC_BANK_CD) AS VAC_BANK_CD, ACCT.VAC_ID, TO_CHAR(TO_DATE(RSV.AC_REG_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS AC_REG_DT, BOND.SUM_PRC AS TOTAL_PRIC, RSV.RB_ESTI, INOUT.SUM_PRIC AS INOUT_TOTAL, FN_GET_CODENM(DECODE(RSV.CR_TP, '1', 'MSP0033', '2', 'MSP0034', 'MSP0035'), RCIV1.TP_JINH) AS TP_JINH, FN_GET_CODENM('MSP0032', RSV.END_YN ) AS END_YN, TO_CHAR(TO_DATE(RSV.RB_STRT_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS RB_STRT_DT, RSV.RB_RATE, RSV.RB_PRID, (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = RSV.REGST_ID GROUP BY USR_NM ) AS REGST_ID, (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = RSV.RVISN_ID GROUP BY USR_NM ) AS RVISN_ID, TO_CHAR(RSV.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM, RSV.CR_SEQ FROM MSP_COURT_RCV RSV, (SELECT B.SUM_PRIC, B.CR_SEQ, MAX(TO_DATE(A.INOUT_DTTM, 'YYYYMMDD')) AS LAST_INOUT_DT FROM MSP_COURT_RCV_INOUT A, (SELECT SUM(INOUT_PRIC) AS SUM_PRIC, CR_SEQ FROM MSP_COURT_RCV_INOUT GROUP BY CR_SEQ ) B WHERE B.CR_SEQ = A.CR_SEQ GROUP BY B.SUM_PRIC, B.CR_SEQ ) INOUT, ( SELECT MAX(JINH.TP_JINH) AS TP_JINH, CR_SEQ FROM (SELECT RCIV.CR_SEQ, RCIV.TP_JINH FROM MSP_COURT_RCV_RCIV RCIV, ( SELECT MAX(STAN_DTTM) AS STAN_DT, CR_SEQ FROM MSP_COURT_RCV_RCIV GROUP BY CR_SEQ) STAN WHERE RCIV.STAN_DTTM = STAN.STAN_DT AND RCIV.CR_SEQ = STAN.CR_SEQ) JINH GROUP BY CR_SEQ ) RCIV1, (SELECT TO_CHAR(MAX(REGST_DTTM), 'YYYY-MM-DD') AS LAST_DT , CR_SEQ FROM MSP_COURT_RCV_RCIV GROUP BY CR_SEQ) RCIV2, (SELECT CR_SEQ, SUM(SUM_PRC) AS SUM_PRC FROM MSP_COURT_RCV_BOND GROUP BY CR_SEQ) BOND, (SELECT VAC_BANK_CD, VAC_ID, CR_SEQ FROM MSP_COURT_RCV_ACCT WHERE VAC_STAT = 'Y') ACCT WHERE RSV.CR_SEQ = INOUT.CR_SEQ (+) AND RSV.CR_SEQ = RCIV1.CR_SEQ (+) AND RSV.CR_SEQ = RCIV2.CR_SEQ (+) AND RSV.CR_SEQ = BOND.CR_SEQ (+) AND RSV.CR_SEQ = ACCT.CR_SEQ (+)
AND TO_CHAR(RSV.REGST_DTTM, 'YYYYMMDDHH24MISS') BETWEEN #{strtDt} || '000000' AND #{endDt} || '235959'
AND RSV.CSTMR_NAME LIKE '%' || #{searchVal} || '%'
AND RSV.CSTMR_RRN = #{searchRrn}
AND RSV.NO_JUDG LIKE '%' || #{searchVal} || '%'
AND RCIV1.TP_JINH = #{tpJinh}
AND RSV.CR_TP = #{crTpCd}
AND RSV.END_YN = #{endYn}
ORDER BY RSV.REGST_DTTM DESC, RSV.CR_SEQ DESC

/* CourtRcvCstmrMapper.getCrCstmrListByExcel */ SELECT TO_CHAR(RSV.REGST_DTTM, 'YYYY-MM-DD') AS FIRST_DT, RCIV2.LAST_DT, TO_CHAR(INOUT.LAST_INOUT_DT, 'YYYY-MM-DD') AS LAST_INOUT_DT, RSV.CSTMR_NAME, CRYPTO_AES256.DEC_AES(RSV.CSTMR_RRN) AS CSTMR_RRN, FN_GET_CODENM('MSP0031', RSV.CR_TP ) AS CR_TP, RSV.CR_COMP, RSV.NO_JUDG, RSV.JUDG_PAN, F_GET_KT_CODE_NM('PPS_VAC', 'BANK_CODE', ACCT.VAC_BANK_CD) AS VAC_BANK_CD, ACCT.VAC_ID, TO_CHAR(TO_DATE(RSV.AC_REG_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS AC_REG_DT, BOND.SUM_PRC AS TOTAL_PRIC, RSV.RB_ESTI, INOUT.SUM_PRIC AS INOUT_TOTAL, FN_GET_CODENM(DECODE(RSV.CR_TP, '1', 'MSP0033', '2', 'MSP0034', 'MSP0035'), RCIV1.TP_JINH) AS TP_JINH, FN_GET_CODENM('MSP0032', RSV.END_YN ) AS END_YN, TO_CHAR(TO_DATE(RSV.RB_STRT_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS RB_STRT_DT, RSV.RB_RATE, RSV.RB_PRID, (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = RSV.REGST_ID GROUP BY USR_NM ) AS REGST_ID, (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = RSV.RVISN_ID GROUP BY USR_NM ) AS RVISN_ID, TO_CHAR(RSV.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM, RSV.CR_SEQ FROM MSP_COURT_RCV RSV, (SELECT B.SUM_PRIC, B.CR_SEQ, MAX(TO_DATE(A.INOUT_DTTM, 'YYYYMMDD')) AS LAST_INOUT_DT FROM MSP_COURT_RCV_INOUT A, (SELECT SUM(INOUT_PRIC) AS SUM_PRIC, CR_SEQ FROM MSP_COURT_RCV_INOUT GROUP BY CR_SEQ ) B WHERE B.CR_SEQ = A.CR_SEQ GROUP BY B.SUM_PRIC, B.CR_SEQ ) INOUT, ( SELECT MAX(JINH.TP_JINH) AS TP_JINH, CR_SEQ FROM (SELECT RCIV.CR_SEQ, RCIV.TP_JINH FROM MSP_COURT_RCV_RCIV RCIV, ( SELECT MAX(STAN_DTTM) AS STAN_DT, CR_SEQ FROM MSP_COURT_RCV_RCIV GROUP BY CR_SEQ) STAN WHERE RCIV.STAN_DTTM = STAN.STAN_DT AND RCIV.CR_SEQ = STAN.CR_SEQ) JINH GROUP BY CR_SEQ ) RCIV1, (SELECT TO_CHAR(MAX(REGST_DTTM), 'YYYY-MM-DD') AS LAST_DT , CR_SEQ FROM MSP_COURT_RCV_RCIV GROUP BY CR_SEQ) RCIV2, (SELECT CR_SEQ, SUM(SUM_PRC) AS SUM_PRC FROM MSP_COURT_RCV_BOND GROUP BY CR_SEQ) BOND, (SELECT VAC_BANK_CD, VAC_ID, CR_SEQ FROM MSP_COURT_RCV_ACCT WHERE VAC_STAT = 'Y') ACCT WHERE RSV.CR_SEQ = INOUT.CR_SEQ (+) AND RSV.CR_SEQ = RCIV1.CR_SEQ (+) AND RSV.CR_SEQ = RCIV2.CR_SEQ (+) AND RSV.CR_SEQ = BOND.CR_SEQ (+) AND RSV.CR_SEQ = ACCT.CR_SEQ (+)
AND TO_CHAR(RSV.REGST_DTTM, 'YYYYMMDDHH24MISS') BETWEEN #{strtDt} || '000000' AND #{endDt} || '235959'
AND RSV.CSTMR_NAME LIKE '%' || #{searchVal} || '%'
AND RSV.CSTMR_RRN = #{searchRrn}
AND RSV.NO_JUDG LIKE '%' || #{searchVal} || '%'
AND RCIV1.TP_JINH = #{tpJinh}
AND RSV.CR_TP = #{crTpCd}
AND RSV.END_YN = #{endYn}
ORDER BY RSV.REGST_DTTM DESC, RSV.CR_SEQ DESC
